blocks.body:
{
    "level": "A2",
    "intro": "W tym temacie dowiesz się, jak używać czasu Past Simple Passive</strong>: jak tworzyć zdania twierdzące, przeczące i pytania w czasie Past Passive.",
    "rules": [
        {
            "label": "Formuła",
            "color": "emerald",
            "text": "<strong>był/był + V3</strong>:",
            "example": "The house was built in 1990."
        },
        {
            "label": "Odmowa",
            "color": "rose",
            "text": "<strong>był/był + nie + V3</strong>:",
            "example": "The letter was not sent."
        },
        {
            "label": "Pytanie",
            "color": "blue",
            "text": "<strong>Był/był + S + V3?</strong>:",
            "example": "Was the house built in 1990?"
        }
    ]
}

{
    "title": "1. Wybór był/był",
    "intro": "Czasownik <strong>be</strong> w czasie przeszłym:",
    "items": [
        {
            "label": "Ja/on/ona/ono",
            "title": "był",
            "subtitle": "Zostałem zaproszony. Dom został zbudowany."
        },
        {
            "label": "Ty/My/Oni",
            "title": "był",
            "subtitle": "Powiedziano ci. Zostali aresztowani."
        },
        {
            "label": "Rzeczowniki w liczbie pojedynczej",
            "title": "był",
            "subtitle": "Samochód został skradziony."
        },
        {
            "label": "Rzeczowniki w liczbie mnogiej",
            "title": "był",
            "subtitle": "Złodzieje zostali złapani."
        }
    ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Порядок: <strong>Temat + był/był + V3 (+ przez agenta)</strong>",
            "examples": [
                {
                    "en": "The house was built in 1990.",
                    "ua": "Dom został wybudowany w 1990 roku."
                },
                {
                    "en": "The thieves were caught yesterday.",
                    "ua": "Złodzieje zostali złapani wczoraj."
                },
                {
                    "en": "I was invited to the party.",
                    "ua": "Zostałem zaproszony na imprezę."
                }
            ]
        },
        {
            "label": "Kiedy stosować?",
            "color": "sky",
            "description": "W przypadku <strong>zakończonych działań w przeszłości</strong>:",
            "examples": [
                {
                    "en": "America was discovered in 1492.",
                    "ua": "Amerykę odkryto w 1492 r. (fakt historyczny)"
                },
                {
                    "en": "The letter was sent last week.",
                    "ua": "Listy zostały wysłane w zeszłym tygodniu."
                },
                {
                    "en": "The window was broken during the storm.",
                    "ua": "Podczas burzy pękła szyba."
                }
            ]
        }
    ]
}

{
    "title": "3. Zdania przeczące",
    "sections": [
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Dodaj <strong>nie</strong> po było/było: <strong>Temat + był/był + nie + V3</strong>",
            "examples": [
                {
                    "en": "The email was not sent.",
                    "ua": "Wiadomość e-mail nie została wysłana."
                },
                {
                    "en": "The documents were not signed.",
                    "ua": "Dokumenty nie zostały podpisane."
                },
                {
                    "en": "I was not informed about the meeting.",
                    "ua": "Nie zostałem powiadomiony o spotkaniu."
                }
            ]
        },
        {
            "label": "Skrócone formy",
            "color": "amber",
            "description": "<strong>nie było / nie było</strong> jest używane potocznie:",
            "examples": [
                {
                    "en": "The door wasn't locked.",
                    "ua": "Drzwi nie były zamknięte."
                },
                {
                    "en": "The rooms weren't cleaned yesterday.",
                    "ua": "Wczoraj pokoje nie były sprzątane."
                }
            ]
        }
    ]
}

{
    "title": "4. Zdania pytające",
    "sections": [
        {
            "label": "Pytanie Tak/Nie",
            "color": "blue",
            "description": "Na górze pojawia się <strong>Czy/było</strong>: <strong>Czy/było + Temat + V3?</strong>",
            "examples": [
                {
                    "en": "Was the car repaired?",
                    "ua": "Czy samochód został naprawiony?"
                },
                {
                    "en": "Were the documents signed?",
                    "ua": "Czy dokumenty zostały podpisane?"
                },
                {
                    "en": "Was she invited to the party?",
                    "ua": "Czy została zaproszona na imprezę?"
                }
            ]
        },
        {
            "label": "Jakie pytanie",
            "color": "sky",
            "description": "<strong>Jakie-słowo + było/było + Temat + V3?</strong>",
            "examples": [
                {
                    "en": "When was the house built?",
                    "ua": "Kiedy dom został zbudowany?"
                },
                {
                    "en": "Where was the car found?",
                    "ua": "Gdzie znalazłeś samochód?"
                },
                {
                    "en": "Why were they arrested?",
                    "ua": "Dlaczego zostali aresztowani?"
                }
            ]
        },
        {
            "label": "Krótkie odpowiedzi",
            "color": "amber",
            "description": "Odpowiedzi zawierające <strong>Tak/Nie + był/był (nie)</strong>:",
            "examples": [
                {
                    "en": "Was the letter sent? — Yes, it was. / No, it wasn't.",
                    "ua": "Czy listy zostały wysłane? - Tak. / NIE."
                },
                {
                    "en": "Were they informed? — Yes, they were. / No, they weren't.",
                    "ua": "Czy zostali powiadomieni? - Tak. / NIE."
                }
            ]
        }
    ]
}

{
    "title": "5. Aktywny kontra pasywny: czas przeszły prosty",
    "intro": "Porównanie elementów aktywnych i pasywnych w przeszłości:",
    "rows": [
        {
            "en": "Active: Tom wrote the letter yesterday.",
            "ua": "Tomek napisał wczoraj list.",
            "note": "→ Passive: The letter was written yesterday."
        },
        {
            "en": "Active: They built this house in 1990.",
            "ua": "Zbudowali ten dom w 1990 roku.",
            "note": "→ Passive: This house was built in 1990."
        },
        {
            "en": "Active: Someone stole my bike.",
            "ua": "Ktoś ukradł mój rower.",
            "note": "→ Passive: My bike was stolen."
        }
    ],
    "warning": "📌 Oznaczenia czasu (wczoraj, ostatni tydzień, w 1990 r.) pozostają!"
}

{
    "title": "6. Znaczniki czasu dla czasu Past Simple Pasive",
    "sections": [
        {
            "label": "Typowe markery",
            "color": "emerald",
            "description": "Czasu Past Simple Passive często używa się ze znacznikami <strong>czasu przeszłego</strong>:",
            "examples": [
                {
                    "en": "yesterday",
                    "ua": "Raport zakończył się wczoraj."
                },
                {
                    "en": "last week/month/year",
                    "ua": "Samochód został sprzedany w zeszłym tygodniu."
                },
                {
                    "en": "in 1990 / in the 19th century",
                    "ua": "Most wybudowano w 1900 r."
                },
                {
                    "en": "ago (two days ago)",
                    "ua": "Mail został wysłany dwa dni temu."
                }
            ]
        }
    ]
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zły wybór był/był.",
            "wrong": "The documents was signed.",
            "right": "✅ The documents were signed."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Używanie V2 zamiast V3.",
            "wrong": "The house was builded in 1990.",
            "right": "✅ The house was built in 1990."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Pomiń zadawanie pytań.",
            "wrong": "The letter sent yesterday?",
            "right": "✅ Was the letter sent yesterday?"
        }
    ]
}

{
    "title": "Pozostałe strony z podstawami strony biernej",
    "items": [
        {
            "label": "Co to jest głos pasywny?",
            "current": false
        },
        {
            "label": "Forma: być + V3",
            "current": false
        },
        {
            "label": "Czas teraźniejszy prosty pasywny",
            "current": false
        },
        {
            "label": "Past Simple Pasywny (bieżący)",
            "current": true
        }
    ]
}
